            _parentMessage.Limit = limit + sizeOfLengthField + dataLength;
            _buffer.GetBytes(limit + sizeOfLengthField, dst.Slice(0, bytesCopied));

            return bytesCopied;
        }
        
        // Allocates and returns a new byte array
        public byte[] GetLocateBytes()
        {
            const int sizeOfLengthField = 2;
            int limit = _parentMessage.Limit;
            _buffer.CheckLimit(limit + sizeOfLengthField);
            int dataLength = (int)_buffer.Uint16GetLittleEndian(limit);
            byte[] data = new byte[dataLength];
            _parentMessage.Limit = limit + sizeOfLengthField + dataLength;
            _buffer.GetBytes(limit + sizeOfLengthField, data);

            return data;
        }

        public int SetLocate(byte[] src, int srcOffset, int length) =>
            SetLocate(new ReadOnlySpan<byte>(src, srcOffset, length));

        public int SetLocate(ReadOnlySpan<byte> src)
        {
            const int sizeOfLengthField = 2;
            int limit = _parentMessage.Limit;
            _parentMessage.Limit = limit + sizeOfLengthField + src.Length;
            _buffer.Uint16PutLittleEndian(limit, (ushort)src.Length);
            _buffer.SetBytes(limit + sizeOfLengthField, src);

            return src.Length;
        }

        public string GetLocate()
        {
            const int sizeOfLengthField = 2;
            int limit = _parentMessage.Limit;
            _buffer.CheckLimit(limit + sizeOfLengthField);
            int dataLength = (int)_buffer.Uint16GetLittleEndian(limit);
            _parentMessage.Limit = limit + sizeOfLengthField + dataLength;
            return _buffer.GetStringFromBytes(LocateResolvedCharacterEncoding, limit + sizeOfLengthField, dataLength);
        }

        public void SetLocate(string value)
        {
            var encoding = LocateResolvedCharacterEncoding;
            const int sizeOfLengthField = 2;
            int limit = _parentMessage.Limit;
            int byteCount = encoding.GetByteCount(value);

            _parentMessage.Limit = limit + sizeOfLengthField + byteCount;

            _buffer.SetBytesFromString(encoding, value, limit + sizeOfLengthField);
            _buffer.Uint16PutLittleEndian(limit, (ushort)byteCount);
        }

        public override string ToString()
        {
            var sb = new StringBuilder(100);
            var m = new SingleOrderRequestMessage();
            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[SingleOrderRequestMessage](sbeTemplateId=");
            builder.Append(SingleOrderRequestMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(SingleOrderRequestMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != SingleOrderRequestMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(SingleOrderRequestMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != SingleOrderRequestMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(SingleOrderRequestMessage.BlockLength);
            builder.Append("):");

            builder.Append("OrderType=");
            builder.Append(this.OrderType);
            builder.Append('|');
            builder.Append("Staged=");
            builder.Append(this.Staged);
            builder.Append('|');
            builder.Append("ClaimRequire=");
            builder.Append(this.ClaimRequire);
            builder.Append('|');
            builder.Append("Price=");
            builder.Append(this.Price);
            builder.Append('|');
            builder.Append("Quantity=");
            builder.Append(this.Quantity);
            builder.Append('|');
            builder.Append("Side=");
            builder.Append(this.Side);
            builder.Append('|');
            builder.Append("Symbol=");
            builder.Append('\'').Append(GetSymbol()).Append('\'');
            builder.Append('|');
            builder.Append("Account=");
            builder.Append('\'').Append(GetAccount()).Append('\'');
            builder.Append('|');
            builder.Append("Route=");
            builder.Append('\'').Append(GetRoute()).Append('\'');
            builder.Append('|');
            builder.Append("Tag=");
            builder.Append('\'').Append(GetTag()).Append('\'');
            builder.Append('|');
            builder.Append("ClientOrderId=");
            builder.Append('\'').Append(GetClientOrderId()).Append('\'');
            builder.Append('|');
            builder.Append("Locate=");
            builder.Append('\'').Append(GetLocate()).Append('\'');

            this.Limit = originalLimit;

        }
